import"https://cdn.tailwindcss.com";document.getElementById("loginForm").addEventListener("submit",async n=>{n.preventDefault();const s=document.getElementById("username").value,o=document.getElementById("password").value,e=document.getElementById("errorMessage");e.classList.add("hidden");try{const t=await(await fetch("/api/admin/login",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({username:s,password:o})})).json();t.success?(localStorage.setItem("token",t.token),window.location.href="/admin/services"):(e.textContent=t.error||"登录失败，请检查用户名和密码",e.classList.remove("hidden"))}catch{e.textContent="网络错误，请稍后重试",e.classList.remove("hidden")}});
